import{c as e,Q as l,j as a,m as d}from"./chunks/framework.CQqJojvj.js";const x=JSON.parse('{"title":"09 - 操作系统","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/09-os.md","filePath":"bagu/09-os.md","lastUpdated":null}'),i={name:"bagu/09-os.md"};function r(n,t,o,s,h,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="_09-操作系统" tabindex="-1">09 - 操作系统 <a class="header-anchor" href="#_09-操作系统" aria-label="Permalink to &quot;09 - 操作系统&quot;">​</a></h1><blockquote><p>操作系统基础知识在面试中主要考察进程线程、内存管理、IO 模型，和并发编程强相关。</p></blockquote><hr><h2 id="_1-进程和线程" tabindex="-1">1. 进程和线程 <a class="header-anchor" href="#_1-进程和线程" aria-label="Permalink to &quot;1. 进程和线程&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">进程</th><th style="text-align:left;">线程</th></tr></thead><tbody><tr><td style="text-align:left;">定义</td><td style="text-align:left;">资源分配的基本单位</td><td style="text-align:left;">CPU 调度的基本单位</td></tr><tr><td style="text-align:left;">内存</td><td style="text-align:left;">各进程独立地址空间</td><td style="text-align:left;">同进程内线程共享地址空间</td></tr><tr><td style="text-align:left;">通信</td><td style="text-align:left;">IPC（管道、消息队列、共享内存、Socket）</td><td style="text-align:left;">共享内存（需要注意同步）</td></tr><tr><td style="text-align:left;">切换开销</td><td style="text-align:left;">大（切换页表、TLB 刷新等）</td><td style="text-align:left;">小（同进程内只需切换寄存器和栈）</td></tr><tr><td style="text-align:left;">崩溃影响</td><td style="text-align:left;">不会影响其他进程</td><td style="text-align:left;">可能导致整个进程崩溃</td></tr></tbody></table><h3 id="协程-coroutine" tabindex="-1">协程（Coroutine） <a class="header-anchor" href="#协程-coroutine" aria-label="Permalink to &quot;协程（Coroutine）&quot;">​</a></h3><p>一种用户态的轻量级线程，调度由程序自身控制而非内核。Go 的 Goroutine、Kotlin 的协程、Java 的虚拟线程（Virtual Threads, JDK 21）都是协程的实现。</p><p><strong>Virtual Threads 的优势：</strong> 线程数可以达到百万级（传统 OS 线程数千个就会 OOM），IO 操作自动 yield 而不是阻塞 OS 线程。</p><hr><h2 id="_2-进程间通信-ipc" tabindex="-1">2. 进程间通信（IPC） <a class="header-anchor" href="#_2-进程间通信-ipc" aria-label="Permalink to &quot;2. 进程间通信（IPC）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">管道（Pipe）</td><td style="text-align:left;">半双工，父子进程间通信</td></tr><tr><td style="text-align:left;">命名管道（FIFO）</td><td style="text-align:left;">任意进程间通信</td></tr><tr><td style="text-align:left;">消息队列</td><td style="text-align:left;">异步消息传递，支持多对多</td></tr><tr><td style="text-align:left;">共享内存</td><td style="text-align:left;">最快的方式，但需要同步机制</td></tr><tr><td style="text-align:left;">信号量（Semaphore）</td><td style="text-align:left;">用于进程间同步，不是数据传递</td></tr><tr><td style="text-align:left;">Socket</td><td style="text-align:left;">支持跨网络通信</td></tr></tbody></table><hr><h2 id="_3-死锁" tabindex="-1">3. 死锁 <a class="header-anchor" href="#_3-死锁" aria-label="Permalink to &quot;3. 死锁&quot;">​</a></h2><h3 id="四个必要条件" tabindex="-1">四个必要条件 <a class="header-anchor" href="#四个必要条件" aria-label="Permalink to &quot;四个必要条件&quot;">​</a></h3><ol><li><strong>互斥</strong> — 资源只能被一个进程占有</li><li><strong>占有并等待</strong> — 占有一个资源的同时等待另一个</li><li><strong>不可抢占</strong> — 资源不能被强制释放</li><li><strong>循环等待</strong> — 形成一个循环等待链</li></ol><h3 id="避免死锁的方式" tabindex="-1">避免死锁的方式 <a class="header-anchor" href="#避免死锁的方式" aria-label="Permalink to &quot;避免死锁的方式&quot;">​</a></h3><ol><li><strong>破坏循环等待</strong> — 统一获取锁的顺序（如按资源 ID 升序加锁）</li><li><strong>破坏占有并等待</strong> — 一次性申请所有资源</li><li><strong>引入超时</strong> — <code>tryLock(timeout)</code> 获取不到就释放已有资源</li><li><strong>死锁检测</strong> — 定期检测是否有死锁，有则强制释放</li></ol><hr><h2 id="_4-内存管理" tabindex="-1">4. 内存管理 <a class="header-anchor" href="#_4-内存管理" aria-label="Permalink to &quot;4. 内存管理&quot;">​</a></h2><h3 id="虚拟内存" tabindex="-1">虚拟内存 <a class="header-anchor" href="#虚拟内存" aria-label="Permalink to &quot;虚拟内存&quot;">​</a></h3><p>每个进程有自己的虚拟地址空间，通过 MMU（内存管理单元）将虚拟地址映射到物理地址。</p><p><strong>好处：</strong></p><ol><li>进程隔离（一个进程无法访问另一个进程的内存）</li><li>物理内存利用率更高（按需分页 + 页面置换）</li><li>简化程序加载（可加载到非连续物理内存中）</li></ol><h3 id="缺页中断" tabindex="-1">缺页中断 <a class="header-anchor" href="#缺页中断" aria-label="Permalink to &quot;缺页中断&quot;">​</a></h3><p>当虚拟地址对应的物理页面不在内存中时，触发缺页中断：</p><ol><li>检查访问是否合法</li><li>从磁盘加载页面到内存</li><li>更新页表映射</li><li>重新执行引起缺页的指令</li></ol><hr><h2 id="_5-io-模型" tabindex="-1">5. IO 模型 <a class="header-anchor" href="#_5-io-模型" aria-label="Permalink to &quot;5. IO 模型&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">模型</th><th style="text-align:left;">说明</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;">阻塞 IO</td><td style="text-align:left;">应用进程阻塞直到数据准备好</td><td style="text-align:left;">简单但效率低</td></tr><tr><td style="text-align:left;">非阻塞 IO</td><td style="text-align:left;">轮询检查数据是否准备好</td><td style="text-align:left;">消耗 CPU</td></tr><tr><td style="text-align:left;">IO 多路复用</td><td style="text-align:left;">select/poll/epoll 监听多个 fd</td><td style="text-align:left;">单线程管理多个连接</td></tr><tr><td style="text-align:left;">信号驱动 IO</td><td style="text-align:left;">内核发 SIGIO 信号通知就绪</td><td style="text-align:left;">不常用</td></tr><tr><td style="text-align:left;">异步 IO</td><td style="text-align:left;">内核完成所有操作后通知</td><td style="text-align:left;">真正的异步（Java NIO2 AIO）</td></tr></tbody></table><h3 id="select-poll-epoll-区别" tabindex="-1">select / poll / epoll 区别 <a class="header-anchor" href="#select-poll-epoll-区别" aria-label="Permalink to &quot;select / poll / epoll 区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">select</th><th style="text-align:left;">poll</th><th style="text-align:left;">epoll</th></tr></thead><tbody><tr><td style="text-align:left;">数据结构</td><td style="text-align:left;">固定大小数组</td><td style="text-align:left;">链表</td><td style="text-align:left;">红黑树 + 就绪链表</td></tr><tr><td style="text-align:left;">fd 数量限制</td><td style="text-align:left;">1024（可改编译）</td><td style="text-align:left;">无限制</td><td style="text-align:left;">无限制</td></tr><tr><td style="text-align:left;">扫描方式</td><td style="text-align:left;">遍历所有 fd (O(n))</td><td style="text-align:left;">遍历所有 fd (O(n))</td><td style="text-align:left;">只返回就绪 fd (O(1))</td></tr><tr><td style="text-align:left;">触发方式</td><td style="text-align:left;">水平触发</td><td style="text-align:left;">水平触发</td><td style="text-align:left;">支持 ET/LT</td></tr></tbody></table><hr><h2 id="_6-用户态和内核态" tabindex="-1">6. 用户态和内核态 <a class="header-anchor" href="#_6-用户态和内核态" aria-label="Permalink to &quot;6. 用户态和内核态&quot;">​</a></h2><p><strong>切换场景：</strong> 系统调用（read/write）、中断、异常。</p><p><strong>切换开销：</strong></p><ol><li>保存用户态寄存器、PC、栈指针</li><li>切换到内核栈</li><li>修改 CPU 特权级</li><li>完成后恢复用户态上下文</li></ol><p><strong>零拷贝：</strong> 避免 CPU 将数据从内核空间拷贝到用户空间。Kafka 使用 <code>sendfile()</code> 系统调用，数据从 Page Cache 直接发送到网卡，不经过用户态。</p>',37)])])}const y=e(i,[["render",r]]);export{x as __pageData,y as default};
